/// A test plan whose `.xctestplan` file is generated by Tuist.
///
/// Use this to describe a test plan in Swift instead of maintaining a static `.xctestplan` file.
/// By default the file is written to Tuist's derived directory next to the project or workspace,
/// the same location Tuist uses for synthesized Info.plists and other generated artefacts, so
/// `Project.swift` stays the single source of truth.
///
/// Pass an explicit `path` when you need the generated file at a specific location — for example
/// when invoking `xcodebuild -testPlan` from CI and wanting a predictable checked-in location.
///
/// Pair with `TestAction.testPlans(_:)` to attach generated plans to a scheme.
public struct TestPlan: Equatable, Codable, Sendable {
    /// Name of the test plan. Used as the filename of the generated `.xctestplan` (when no explicit
    /// `path` is provided) and displayed in the Xcode test plan picker.
    public var name: String

    /// Optional explicit path for the generated `.xctestplan` file. When `nil`, Tuist writes it to
    /// `Derived/TestPlans/<name>.xctestplan` next to the manifest.
    public var path: Path?

    /// Test targets included in the test plan.
    public var testTargets: [TestableTarget]

    /// Whether this plan is the default plan for the scheme.
    public var isDefault: Bool

    public init(
        name: String,
        path: Path? = nil,
        testTargets: [TestableTarget],
        isDefault: Bool = false
    ) {
        self.name = name
        self.path = path
        self.testTargets = testTargets
        self.isDefault = isDefault
    }
}
